module RefModule(
   input                      clk,
   input                      rst,
   output                     done,
   input                      rq_vld_in,
   input                      rs_vld_in
);reg   [63:0]               rq_count_s;
   reg   [63:0]               rs_count_s;

   always @(posedge clk)
   begin
      if (rst == 1)              rq_count_s <= 64'd0;
      else if (rq_vld_in == 1)   rq_count_s <= rq_count_s + 64'd1;

      if (rst == 1)              rs_count_s <= 64'd0;
      else if (rs_vld_in == 1)   rs_count_s <= rs_count_s + 64'd1;

   end

     wire _n01 = rq_count_s[0] ^ rs_count_s[0];
  wire _n02 = rq_count_s[1] ^ rs_count_s[1];
  wire _n03 = rq_count_s[2] ^ rs_count_s[2];
  wire _n04 = rq_count_s[3] ^ rs_count_s[3];
  assign done = ~_n01 & ~_n02 & ~_n03 & ~_n04;

endmodule
